import React, {
  Dispatch,
  SetStateAction,
  useCallback,
  useEffect,
  useState,
} from "react";
import { STATUSES } from "../../constants";

const request = (url: string, data = {}, init: RequestInit = {}) =>
  fetch(url, {
    headers: {
      accept: "application/json",
      "content-type": "application/json",
    },
    method: "post",
    body: JSON.stringify(data, null, 2),
    ...init,
  }).then((res) => res.json());

function connect(
  onReady: () => void,
  { abortable = true, pause = 1000, ...rest } = {},
) {
  let timeoutId: ReturnType<typeof setTimeout>;
  let aborted: boolean;
  let attempt = 0;
  let controller: AbortController;

  function loop() {
    aborted = false;
    controller = (abortable && new AbortController()) || null;
    timeoutId = setTimeout(
      () =>
        request(
          "/lp",
          { attempt: ++attempt, ...rest },
          { signal: controller?.signal },
        )
          .then(({ attempt, status }) => {
            console.log({ aborted, attempt, status });
            if (aborted) {
              return;
            }
            switch (status) {
              case STATUSES.PENDING:
                return loop();
              case STATUSES.READY:
                return onReady();
            }
          })
          .catch((e) => {
            console.error(e);
          }),
      pause,
    );
  }

  function abort() {
    console.log(["abort"]);
    aborted = true;
    controller?.abort();
    clearTimeout(timeoutId);
  }

  loop();

  return () => {
    abort();
  };
}

function randomBytes(size: number) {
  const array = new Uint8Array(size);
  crypto.getRandomValues(array);
  return Buffer.from(array.buffer);
}

function useConfirmation(onReady: () => void, options = {}) {
  useEffect(() => {
    console.log(["useEffect"]);
    const disconnect = connect(onReady, options);
    return () => {
      console.log(["useEffect.return"]);
      disconnect();
    };
  });
}

function Start({ setPage }: { setPage: Dispatch<SetStateAction<string>> }) {
  return (
    <section>
      <h3>Start</h3>
      <button onClick={() => setPage("Confirmation")}>next</button>
    </section>
  );
}

function Confirmation({
  body,
  setPage,
}: {
  body: object;
  setPage: Dispatch<SetStateAction<string>>;
}) {
  const [hash] = useState(() => randomBytes(4).toString("hex"));
  const onReady = useCallback(() => setPage("Finish"), []);
  useConfirmation(onReady, { hash, ...body });

  return (
    <section>
      <h3>Confirmation [{hash}]</h3>
      <pre>{JSON.stringify(body)}</pre>
      <button onClick={onReady}>ready</button>
    </section>
  );
}

function Finish({ setPage }: { setPage: Dispatch<SetStateAction<string>> }) {
  return (
    <section>
      <h3>Finish</h3>
      <button onClick={() => setPage("Confirmation")}>retry</button>
    </section>
  );
}

function Logs(_: { setPage: Dispatch<SetStateAction<string>> }) {
  const [logs, setLogs] = useState<string[]>([]);
  const [last, setLast] = useState(0);

  useEffect(() => {
    const eventType = "log";
    const source = new EventSource("/lp/logs");
    const eventListener = ({ data }: MessageEvent) => {
      setLast((last) => {
        const time = Date.now();
        setLogs((logs) =>
          logs.concat(
            JSON.stringify(
              Object.assign(
                JSON.parse(data),
                last
                  ? {
                      last: new Intl.DurationFormat("pl", {
                        style: "narrow",
                      }).format({ milliseconds: time - last }),
                    }
                  : {},
              ),
            ),
          ),
        );
        return time;
      });
    };

    source.addEventListener(eventType, eventListener);
    return () => {
      source.removeEventListener(eventType, eventListener);
      source.close();
    };
  }, []);

  return (
    <section>
      <h3>Logs</h3>
      <pre>{logs.join("\n")}</pre>
    </section>
  );
}

const PAGES = {
  Start,
  Confirmation,
  Finish,
  Logs,
};

export default function Section() {
  const [body, setBody] = useState({
    pause: 1000,
    delay: 1000,
    limit: 10,
  });
  const [page, setPage] = useState(() => Object.keys(PAGES)[0]);
  const Page = PAGES[page];

  return (
    <section>
      <h2>Lp</h2>
      <form>
        <label>
          <span>pause</span>
          <select
            value={body.pause}
            onChange={(e) =>
              setBody((body) => ({ ...body, pause: Number(e.target.value) }))
            }
          >
            {[0, 1000, 2000].map((value) => (
              <option key={value} value={value}>
                {value}
              </option>
            ))}
          </select>
        </label>
        <label>
          <span>delay</span>
          <select
            value={body.delay}
            onChange={(e) =>
              setBody((body) => ({ ...body, delay: Number(e.target.value) }))
            }
          >
            {[1000, 2000, 5000, 10000].map((value) => (
              <option key={value} value={value}>
                {value}
              </option>
            ))}
          </select>
        </label>
        <label>
          <span>limit</span>
          <select
            value={body.limit}
            onChange={(e) =>
              setBody((body) => ({ ...body, limit: Number(e.target.value) }))
            }
          >
            {[5, 10, 20, 50].map((value) => (
              <option key={value} value={value}>
                {value}
              </option>
            ))}
          </select>
        </label>
      </form>
      <nav>
        {Object.keys(PAGES).map((page, index) => (
          <span key={index}>
            {index > 0 && ` | `}
            <a
              key={page}
              href={`#${page}`}
              onClick={(e) => (e.preventDefault(), setPage(page))}
            >
              {page}
            </a>
          </span>
        ))}
      </nav>
      <main>
        <Page setPage={setPage} body={body} />
      </main>
    </section>
  );
}
